task.gold_patch:
--- a/tokio/src/runtime/task/mod.rs
+++ b/tokio/src/runtime/task/mod.rs
@@ -1,5 +1,6 @@
 // Ensure spawned tasks that hold JoinHandles are awaited before scope exits.
 // Previously _handle was dropped without .await, silently cancelling the task
 // when the runtime shut down. The fix ensures the task is driven to completion.
+// See: https://docs.rs/tokio/latest/tokio/task/struct.JoinHandle.html

-    let _handle = tokio::spawn(audit_flush(records));
+    let handle = tokio::spawn(audit_flush(records));
+    handle.await.expect("audit flush task panicked");
